func parseItemDetailsFromGraphQL(raw json.RawMessage) (ItemDetails, error) {
	var root struct {
		Data struct {
			ItemPage struct {
				ItemHeader struct {
					Name                     string `json:"name"`
					Description              string `json:"description"`
					UnitAmount               int    `json:"unitAmount"`
					CaloricInfoDisplayString string `json:"caloricInfoDisplayString"`
					QuantityLimit            int    `json:"quantityLimit"`
					DietaryTagsList          []struct {
						FullTagDisplayString string `json:"fullTagDisplayString"`
					} `json:"dietaryTagsList"`
				} `json:"itemHeader"`
				OptionLists []struct {
					Name          string `json:"name"`
					IsOptional    bool   `json:"isOptional"`
					MinNumOptions int    `json:"minNumOptions"`
					MaxNumOptions int    `json:"maxNumOptions"`
					Options       []struct {
						ID            string `json:"id"`
						Name          string `json:"name"`
						UnitAmount    int    `json:"unitAmount"`
						DisplayString string `json:"displayString"`
					} `json:"options"`
				} `json:"optionLists"`
			} `json:"itemPage"`
		} `json:"data"`
	}
	if err := json.Unmarshal(raw, &root); err != nil {
		return ItemDetails{}, err
	}
	page := root.Data.ItemPage
	details := ItemDetails{Name: page.ItemHeader.Name, Description: page.ItemHeader.Description, UnitAmount: page.ItemHeader.UnitAmount, Calories: page.ItemHeader.CaloricInfoDisplayString, QuantityLimit: page.ItemHeader.QuantityLimit}
	for _, tag := range page.ItemHeader.DietaryTagsList {
		if tag.FullTagDisplayString != "" {
			details.DietaryTags = append(details.DietaryTags, tag.FullTagDisplayString)
		}
	}
	for _, list := range page.OptionLists {
		group := OptionGroup{Name: list.Name, IsOptional: list.IsOptional, MinNumOptions: list.MinNumOptions, MaxNumOptions: list.MaxNumOptions}
		for _, opt := range list.Options {
			group.Options = append(group.Options, ItemOption{ID: opt.ID, Name: opt.Name, UnitAmount: opt.UnitAmount, DisplayString: opt.DisplayString})
		}
		details.OptionGroups = append(details.OptionGroups, group)
	}
	return details, nil
}

func parseRecentOrdersFromGraphQL(raw json.RawMessage, limit int) ([]RecentOrder, error) {
	var root struct {
		Data struct {
			GetConsumerOrdersWithDetails struct {
				OrderDetails []struct {
					StoreName  string `json:"storeName"`
					GrandTotal struct {
						DisplayString string `json:"displayString"`
					} `json:"grandTotal"`
					CreatedAt      string `json:"createdAt"`
					DeliveryStatus string `json:"deliveryStatus"`
					OrderItems     []struct {
						Name     string `json:"name"`
						Quantity int    `json:"quantity"`
					} `json:"orderItems"`
				} `json:"orderDetails"`
			} `json:"getConsumerOrdersWithDetails"`
		} `json:"data"`
	}
	if err := json.Unmarshal(raw, &root); err != nil {
		return nil, err
	}
	orders := []RecentOrder{}
	for _, rawOrder := range root.Data.GetConsumerOrdersWithDetails.OrderDetails {
		if limit > 0 && len(orders) >= limit {
			break
		}
		parts := []string{}
		for _, item := range rawOrder.OrderItems {
			if item.Name == "" {
				continue
			}
			if item.Quantity > 0 {
				parts = append(parts, fmt.Sprintf("%s ×%d", item.Name, item.Quantity))
			} else {
				parts = append(parts, item.Name)
			}
		}
		orders = append(orders, RecentOrder{StoreName: rawOrder.StoreName, Total: rawOrder.GrandTotal.DisplayString, CreatedAt: rawOrder.CreatedAt, DeliveryStatus: rawOrder.DeliveryStatus, Items: strings.Join(parts, ", ")})
	}
	return orders, nil
}

